import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import { fetchTrending, fetchCategories } from '../store/slices/venueSlice';
import { toggleAIChat } from '../store/slices/uiSlice';
import StoriesFeed from '../components/StoriesFeed';
import VenueCard from '../components/VenueCard';
import ReservationModal from '../components/ReservationModal';

export default function Home() {
  const dispatch = useDispatch();
  const { trending, categories } = useSelector((state) => state.venues);
  const { reservationModal } = useSelector((state) => state.ui);
  const [city, setCity] = useState('');

  useEffect(() => {
    dispatch(fetchTrending());
    dispatch(fetchCategories());
  }, [dispatch]);

  return (
    <div className="min-h-screen">
      {/* Hero */}
      <section className="relative min-h-screen flex items-center justify-center bg-hero-gradient overflow-hidden pt-16">
        {/* Background glows */}
        <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-primary/10 rounded-full blur-3xl" />
        <div className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-accent-purple/10 rounded-full blur-3xl" />

        <div className="relative z-10 text-center px-4 max-w-4xl mx-auto">
          <div className="inline-flex items-center space-x-2 bg-primary/10 border border-primary/30 rounded-full px-4 py-2 mb-8">
            <span className="w-2 h-2 bg-green-400 rounded-full animate-pulse" />
            <span className="text-sm text-primary font-medium">Live venues near you</span>
          </div>

          <h1 className="font-display font-bold text-5xl md:text-7xl text-white mb-6 leading-tight">
            Decide where to go.
            <br />
            <span className="text-primary">Right now.</span>
          </h1>

          <p className="text-xl text-gray-400 mb-10 max-w-2xl mx-auto">
            Real-time venue discovery, live crowd vibes, and instant reservations —
            all in one place. Your night starts here.
          </p>

          {/* Search bar */}
          <div className="flex flex-col sm:flex-row gap-3 max-w-xl mx-auto">
            <input
              type="text"
              placeholder="Enter your city..."
              value={city}
              onChange={(e) => setCity(e.target.value)}
              className="input flex-1"
            />
            <Link
              to={`/discover${city ? `?city=${encodeURIComponent(city)}` : ''}`}
              className="btn-primary whitespace-nowrap"
            >
              Explore Now
            </Link>
          </div>

          <p className="mt-4 text-gray-600 text-sm">
            or{' '}
            <button
              onClick={() => dispatch(toggleAIChat())}
              className="text-primary hover:underline"
            >
              ask our AI guide ✨
            </button>
          </p>
        </div>

        {/* Scroll indicator */}
        <div className="absolute bottom-8 left-1/2 -translate-x-1/2 animate-bounce">
          <svg className="w-6 h-6 text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
          </svg>
        </div>
      </section>

      {/* Live Stories */}
      <section className="py-12 px-4 max-w-7xl mx-auto">
        <div className="flex items-center justify-between mb-6">
          <div>
            <h2 className="font-display font-bold text-2xl text-white">Live Stories</h2>
            <p className="text-gray-500 text-sm">See what's happening right now</p>
          </div>
          <Link to="/discover" className="text-primary text-sm hover:underline">View all →</Link>
        </div>
        <StoriesFeed city={city} />
      </section>

      {/* Categories */}
      <section className="py-8 px-4 max-w-7xl mx-auto">
        <h2 className="font-display font-bold text-2xl text-white mb-6">Browse by Category</h2>
        <div className="flex flex-wrap gap-3">
          {categories.map((cat) => (
            <Link
              key={cat.id}
              to={`/discover?category=${cat.slug}`}
              className="flex items-center space-x-2 px-5 py-3 card hover:border-primary/50 transition-all hover:-translate-y-0.5 font-medium"
            >
              <span className="text-xl">{cat.icon}</span>
              <span className="text-white text-sm">{cat.name}</span>
            </Link>
          ))}
        </div>
      </section>

      {/* Trending */}
      <section className="py-12 px-4 max-w-7xl mx-auto">
        <div className="flex items-center justify-between mb-6">
          <div>
            <h2 className="font-display font-bold text-2xl text-white">🔥 Trending Tonight</h2>
            <p className="text-gray-500 text-sm">Highest energy spots right now</p>
          </div>
          <Link to="/discover?ordering=-busy_level" className="text-primary text-sm hover:underline">See all →</Link>
        </div>

        {trending.length > 0 ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {trending.map((venue) => (
              <VenueCard key={venue.id} venue={venue} />
            ))}
          </div>
        ) : (
          <div className="text-center py-20 text-gray-500">
            <p className="text-4xl mb-4">🌃</p>
            <p>No venues open right now. Check back tonight!</p>
          </div>
        )}
      </section>

      {/* CTA */}
      <section className="py-20 px-4">
        <div className="max-w-4xl mx-auto text-center card p-12 bg-gradient-to-br from-primary/10 to-accent-purple/10 border-primary/20">
          <h2 className="font-display font-bold text-4xl text-white mb-4">Own a venue?</h2>
          <p className="text-gray-400 text-lg mb-8">
            Join Way Out and reach thousands of customers looking for their next night out.
            Manage reservations, post live stories, and grow your business.
          </p>
          <Link to="/register" className="btn-primary text-lg px-8 py-4">
            List Your Venue
          </Link>
        </div>
      </section>

      {reservationModal.open && <ReservationModal />}
    </div>
  );
}
